1	import { describe, it, expect } from "vitest";
2	import { run } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Simplest case
6	  it("empty item list — premium 5 G (only processing fee)", () => {
7	    const result = run({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result.results[0]).toEqual({ premium: 5 });
12	  });
13	
14	  // Base premiums for single items (with processing fee)
15	  it("single sword (first insurance) — premium 115 G (100 base + 10 first + 5 fee)", () => {
16	    const result = run({
17	      customer: { yearsWithMHPCO: 0 },
18	      steps: [{ op: "quote", items: [{ type: "sword" }] }],
19	    });
20	    expect(result.results[0]).toEqual({ premium: 115 });
21	  });
22	  it("single amulet (first insurance) — premium 71 G (60 base + 6 first + 5 fee)", () => {
23	    const result = run({
24	      customer: { yearsWithMHPCO: 0 },
25	      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
26	    });
27	    expect(result.results[0]).toEqual({ premium: 71 });
28	  });
29	  it("single staff (first insurance) — premium 93 G (80 base + 8 first + 5 fee)", () => {
30	    const result = run({
31	      customer: { yearsWithMHPCO: 0 },
32	      steps: [{ op: "quote", items: [{ type: "staff" }] }],
33	    });
34	    expect(result.results[0]).toEqual({ premium: 93 });
35	  });
36	  it("single potion (first insurance) — premium 49 G (40 base + 4 first + 5 fee)", () => {
37	    const result = run({
38	      customer: { yearsWithMHPCO: 0 },
39	      steps: [{ op: "quote", items: [{ type: "potion" }] }],
40	    });
41	    expect(result.results[0]).toEqual({ premium: 49 });
42	  });
43	
44	  // Components
45	  it("single rune (first insurance) — premium 33 G (25 base + 2.5 first + 5 fee = 32.5 → 33)", () => {
46	    const result = run({
47	      customer: { yearsWithMHPCO: 0 },
48	      steps: [{ op: "quote", items: [{ type: "rune" }] }],
49	    });
50	    expect(result.results[0]).toEqual({ premium: 33 });
51	  });
52	  it.todo("single moonstone — premium 30 G (25 base + 5 fee)");
53	
54	  // Building block of 3 alike components
55	  it.todo("2 runes — base premium 50 G (no block)");
56	  it.todo("3 runes — base premium 60 G (block applies)");
57	  it.todo("4 runes — base premium 100 G (no block, requires exactly 3)");
58	  it.todo("7 runes — base premium 175 G");
59	
60	  // Alike components — different types are not alike
61	  it.todo("2 runes + 1 moonstone — base premium 75 G (no block, different types)");
62	  it.todo("3 runes + 3 moonstones — base premium 120 G (two separate blocks)");
63	
64	  // Item-specific modifiers
65	  it.todo("cursed sword — base 100 + 50 curse + 5 fee = 155 G");
66	  it.todo("sword with enchantment 5 — base 100 + 30 high-ench + 5 fee = 135 G");
67	  it.todo("sword with enchantment 4 — no high-ench surcharge = 105 G");
68	  it.todo("cursed sword with enchantment 5 — base 100 + 50 curse + 30 high-ench + 5 fee = 185 G");
69	
70	  // Customer-level modifiers
71	  it.todo("customer with 2 years — 20% loyalty discount applies");
72	  it.todo("customer with 1 year — no loyalty discount");
73	  it.todo("first contract — 10% first insurance surcharge applies");
74	  it.todo("second contract — 15% follow-up discount applies");
75	
76	  // Modifier scope on multi-item policies
77	  it.todo("cursed sword + plain amulet — base 160 G, +50 curse = 210 G + fee = 215 G");
78	
79	  // Rounding in MHPCO's favor
80	  it.todo("premium yielding 197.5 G — rounded up to 198 G");
81	  it.todo("payout yielding 350.5 G — rounded down to 350 G");
82	
83	  // Integration examples
84	  it.todo("newcomer cursed sword — premium 165 G");
85	  it.todo("long-standing customer's second contract with cursed sword ench 7 — premium 160 G");
86	
87	  // Claims — basic deductible
88	  it.todo("regular sword damage 500 G — payout 400 G (deductible)");
89	  it.todo("rune damage 200 G — payout 100 G (deductible, no special clause)");
90	
91	  // Claims — enchantment threshold
92	  it.todo("dragon-material sword ench 8, damage 1000 G — payout 400 G (50% then deductible)");
93	  it.todo("dragon-material sword ench 9, damage 1000 G — payout 400 G (50% wins, then deductible)");
94	  it.todo("dragon-material sword ench 5, damage 800 G — payout 700 G (dragon full, then deductible)");
95	  it.todo("steel sword ench 9, damage 1000 G — payout 400 G (50% then deductible)");
96	
97	  // Claims — multiple damages
98	  it.todo("dragon attack damages sword 500 + amulet 300 — payout 600 G (deductible per item)");
99	
100	  // Multiple items of the same type
101	  it.todo("two swords policy — insurance sum 2000 G, cap 4000 G");
102	  it.todo("damages array references more items than policy — CLI rejects");
103	
104	  // Cap exhaustion
105	  it.todo("sword + amulet — insurance sum 1600 G, cap 3200 G");
106	  it.todo("cursed sword — cap 2000 G (based on unmodified insurance value)");
107	  it.todo("sword + 3 runes block — insurance sum 1750 G (block affects premium only)");
108	  it.todo("sword two successive 1500 G claims — first payout 1400 cap 600, second payout 600 cap 0");
109	
110	  // Edge case errors
111	  it.todo("unknown item type in quote — CLI exits non-zero with stderr");
112	  it.todo("claim references item not in policy — CLI exits non-zero");
113	  it.todo("negative damage amount — CLI exits non-zero");
114	});
