1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	type Item = { type: string };
13	type QuoteStep = { op: "quote"; items: Item[] };
14	type Input = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
15	type QuoteResult = { premium: number };
16	
17	const itemPremium = (item: Item): number => {
18	  const base = BASE_PREMIUM[item.type];
19	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
20	  return base + firstInsuranceSurcharge;
21	};
22	
23	const sumItemPremiums = (items: Item[]): number =>
24	  items.reduce((sum, item) => sum + itemPremium(item), 0);
25	
26	const quotePremium = (step: QuoteStep): QuoteResult => ({
27	  premium: Math.ceil(sumItemPremiums(step.items) + PROCESSING_FEE),
28	});
29	
30	export const run = (input: Input): { results: QuoteResult[] } => ({
31	  results: input.steps.map(quotePremium),
32	});
